// Build the email from a submission that arrived over the OPEN INTERNET — every
// field here is untrusted input, so nothing is interpolated without cleaning.
const b = $input.first().json.body ?? $json.body ?? $json;

// Strip CR/LF before anything reaches a mail HEADER (subject, reply-to). A newline
// in a header field is how you inject extra headers — a Bcc, a forged From. The
// body is free to keep its newlines; headers are not.
const header = (v, max) => String(v ?? '').replace(/[\r\n]+/g, ' ').trim().slice(0, max);

const name = header(b.name, 120) || 'anonymous';
const email = header(b.email, 200);
const source = header(b.source, 60) || 'unknown';
const message = String(b.message ?? '').trim();

// A plausible address, checked only so Reply-To cannot be turned into a header
// payload. This is NOT verification that the address exists or belongs to them.
const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

const subject = `Reckons.AI feedback from ${name} (${source})`;
const body = [
  `From:    ${name} <${emailOk ? email : 'no usable address supplied'}>`,
  `Source:  ${source}`,
  `Sent:    ${header(b.submittedAt, 40) || new Date().toISOString()}`,
  '',
  '---',
  '',
  message,
].join('\n');

// Drop the junk the open webhook will inevitably attract. Length caps are the
// cheap deterministic rule; they are not a spam filter and do not pretend to be.
const valid = message.length > 0 && message.length <= 20000;

return [{ json: { subject, body, replyTo: emailOk ? email : '', valid } }];
